(function(){try{// Look for product containers, product cards, or main content area
const mainContent = document.querySelector('main, #main, .main-content, .search-results, .products, .s-result-list, .s-search-results');
const productElements = document.querySelectorAll('.s-result-item, .product, .product-card, .item, [data-component-type="s-search-result"], [data-asin]');
const gridContainers = document.querySelectorAll('.s-main-slot, .s-search-results, .s-result-list, .grid, .product-grid');

let result = {
  mainContent: mainContent ? mainContent.tagName + (mainContent.id ? '#' + mainContent.id : '') + (mainContent.className ? '.' + mainContent.className.replace(/\s+/g, '.') : '') : 'not found',
  productCount: productElements.length,
  gridContainers: Array.from(gridContainers).map(el => el.tagName + (el.id ? '#' + el.id : '') + (el.className ? '.' + el.className.replace(/\s+/g, '.') : '')).join(', '),
  bodyChildren: document.body.children.length,
  viewportHeight: window.innerHeight,
  scrollY: window.scrollY
};

// Check if there are any hidden or off-screen elements
const allDivs = document.querySelectorAll('div');
const largeDivs = Array.from(allDivs).filter(div => {
  const rect = div.getBoundingClientRect();
  return rect.width > 300 && rect.height > 200;
}).slice(0, 5);

result.largeDivs = largeDivs.map(div => div.tagName + (div.id ? '#' + div.id : '') + (div.className ? '.' + div.className.replace(/\s+/g, '.') : '') + ' ' + rectInfo(div)).join(' | ');

function rectInfo(el) {
  const rect = el.getBoundingClientRect();
  return `w:${Math.round(rect.width)} h:${Math.round(rect.height)} x:${Math.round(rect.x)} y:${Math.round(rect.y)}`;
}

return JSON.stringify(result, null, 2);
}catch(e){return 'Error: '+e.message}})()
